private LogSummary parseLogSummary(String aiResponse) {
    LogSummary summary = new LogSummary();
    String[] lines = aiResponse.split("\n");
    for (String line : lines) {
        if (line.startsWith("SUMMARY:")) {
            summary.setSummary(line.split(":", 2)[1].trim());
        } else if (line.startsWith("ERROR_COUNT:")) {
            try {
                summary.setErrorCount(Integer.parseInt(line.split(":")[1].trim()));
            } catch (Exception e) {
                // Handle exception if needed, e.g., log or ignore
            }
        } else if (line.startsWith("WARNING_COUNT:")) {
            try {
                summary.setWarningCount(Integer.parseInt(line.split(":")[1].trim()));
            } catch (Exception e) {
                // Handle exception if needed, e.g., log or ignore
            }
        } else if (line.startsWith("OVERALL_STATUS:")) {
            summary.setStatus(line.split(":")[1].trim());
        }
    }
    return summary;
}
